        _isInitialized = true;
      } catch (_) {
        await _resetOwned();
        rethrow;
      }
    })();

    _operation = operation;
    try {
      await operation;
    } finally {
      if (identical(_operation, operation)) {
        _operation = Future<void>.value();
      }
    }
  }

