import 'package:get_it/get_it.dart';

class HelpRequestModule {
  static final _getIt = GetIt.instance;
  static bool _isInitialized = false;
  static Future<void>? _operation;
  static int _generation = 0;
  static HelpRequestMediaService? _ownedMediaService;

  static Future<void> init({
    required HelpRequestConfig config,
    HelpRequestMode mode = HelpRequestMode.live,
  }) {
    final generation = _generation;
    return _serialize(() => _initialize(config, mode, generation));
  }

  static bool get isInitialized =>
      _isInitialized && HelpRequestUtils.isConfigured;

  static Future<void> reset() {
    // Invalidate initializations immediately, including one currently waiting for
    // a token. The actual cleanup remains ordered with all other operations.
    _generation++;
    return _serialize(_resetOwned);
  }

  static Future<void> _initialize(
    HelpRequestConfig config,
    HelpRequestMode mode,
    int generation,
  ) async {
    if (generation != _generation || isInitialized) return;

    try {
      if (mode != HelpRequestMode.mock) {
        final token = await config.getToken?.call();
        if (token == null) throw StateError('token is null');
      }

      if (generation != _generation) return;

      // Services may read the configuration while they are being registered.
      HelpRequestUtils.setConfig(config);
      if (!_getIt.isRegistered<HelpRequestMediaService>()) {
        final mediaService = DefaultHelpRequestMediaService();
        _getIt.registerSingleton<HelpRequestMediaService>(mediaService);
        _ownedMediaService = mediaService;
      }
      initHelpRequestLocator();
      await initializeDateFormatting();

      if (generation != _generation) {
        await _resetOwned();
        return;
      }
      _isInitialized = true;
    } catch (_) {
      await _resetOwned();
      rethrow;
    }
  }

  static Future<void> _resetOwned() async {
    await resetHelpRequestLocator();
    final mediaService = _ownedMediaService;
    if (mediaService != null &&
        _getIt.isRegistered<HelpRequestMediaService>() &&
        identical(_getIt<HelpRequestMediaService>(), mediaService)) {
      await _getIt.unregister<HelpRequestMediaService>();
    }
    _ownedMediaService = null;
    HelpRequestUtils.reset();
    _isInitialized = false;
  }

  static Future<void> _serialize(Future<void> Function() action) {
    final current = _operation;
    late final Future<void> operation;
    operation = () async {
      if (current != null) {
        // A failed operation must not poison the queue; its own caller still
        // observes the error through the original future.
        try {
          await current;
        } catch (_) {}
      }
      await action();
    }();

    _operation = operation;
    operation.then<void>(
      (_) {
        if (identical(_operation, operation)) _operation = null;
      },
      onError: (Object _, StackTrace __) {
        if (identical(_operation, operation)) _operation = null;
      },
    );
    return operation;
  }
}
